/// <summary>
/// ETG Vendor has been disabled based on status as OnHold - Added by Datta - 22/07/2024.
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreement, PurchAgreementHeader), FormDataSourceEventType::Activated)]
public static void PurchAgreementHeader_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun element = sender.formRun();

    FormStringControl vendAccountEdit = element.design(0).controlName('PurchAgreementHeader_ETG_Vendor');

    FormComboBoxControl status = element.design(0).controlName('Status_AgreementState');

    FormDataSource PurchAgreementHeader_ds = element.datasource(formDataSourceStr(PurchAgreement, PurchAgreementHeader)) as FormDataSource;

    PurchAgreementHeader purchAgreementHeader = PurchAgreementHeader_ds.cursor();

    // status has been disabled - Added by Datta - 22/07/2024.
    status.allowEdit(false);

    if(purchAgreementHeader.AgreementState == AgreementState::OnHold)
    {
        vendAccountEdit.allowEdit(true);           
    }
    else
    {
        vendAccountEdit.allowEdit(false);           
    }
}

/// <summary>
/// Vendor has been updated based on ETG vendor - Added by Datta - 22/07/2024.
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(PurchAgreement, PurchAgreementHeader_ETG_Vendor), FormControlEventType::Modified)]
public static void PurchAgreementHeader_ETG_Vendor_OnModified(FormControl sender, FormControlEventArgs e)
{
    FormRun element = sender.formRun();

    FormDataSource PurchAgreementHeader_ds = element.datasource(formDataSourceStr(PurchAgreement, PurchAgreementHeader)) as FormDataSource;

    PurchAgreementHeader purchAgreementHeader = PurchAgreementHeader_ds.cursor();

    if(purchAgreementHeader)
    {      
        purchAgreementHeader.VendAccount = purchAgreementHeader.ETG_Vendor;
    }
}
